function getSumString(val){
  let result = [];
  function dfs(string, curstr, sum){
    if(string.length === 0) return;

    if(sum + Number(string) === val){
      result.push(curstr+"+"+string);
      return;
    }

    if(sum - Number(string) === val){
      result.push(curstr+"-"+string);
      return;
    }

    for(let i=0; i<string.length; i++){
      dfs(string.substring(i+1), curstr+"+"+string.substring(0,i+1), sum+Number(string.substring(0,i+1)));
      dfs(string.substring(i+1), curstr+"-"+string.substring(0,i+1), sum-Number(string.substring(0,i+1)));
    }
  }

  dfs('123456789', '', 0);

  return result;
}


