class SumCombine {
public:
    vector<string> calc(string numbers, int sum) {
        vector<string> ret;
        if (numbers.empty()) {
            if (sum == 0) ret.push_back("");
            return ret;
        }
        for (int i = 1; i <= numbers.size(); ++i) {
            string hold = numbers.substr(0, i);
            string left = numbers.substr(i, numbers.size()-i);
            int hold_n = stoi(hold);

            vector<pair<int, string>> remains{{sum+hold_n, "+"}, {sum-hold_n, "-"}};  
            // {result, operator}
            // positive, negative, or other further operations
            for (auto rem : remains) {
                auto sret = calc(left, rem.first);
                if (!sret.empty()) {
                    for (string& s : sret) s = rem.second + hold + s;
                    ret.insert(ret.end(), sret.begin(), sret.end());
                }
            }
        }
        return ret;
    }
};

int main() {
    auto res = SumCombine().calc("123456789", 100);
    for (string s : res) cout << s << endl;
}
