class Solution {
    List<String> results;
    public List<String> sumTo(String s, int total) {
        results = new ArrayList<>();

        helper(s, 0, total, 0, 0,"");
        return results;
    }

    public void helper(String s, int pos, int total, int current, int carry, String output){
        if (pos == s.length()){
            if(current == total && carry ==0)
                results.add(output);

            return;
        }

        int val = Character.getNumericValue(s.charAt(pos));
        carry = carry*10+val;

        helper(s, pos+1, total, current, carry, output);
        helper(s, pos+1, total, current-carry,0, output + '-' + String.valueOf(carry));
        helper(s, pos+1, total, current+carry,0, (output.length() > 0 ? output + '+' : "") + String.valueOf(carry));
    }
}
